"use client";

import { motion, useScroll, useTransform, useSpring } from "framer-motion";
import { useRef } from "react";
import Image from "next/image";

const cards = [
  { title: "Newborn Baby", desc: "Beautiful baby moments.", image: "/newborn.jpg" },
  { title: "Pre Wedding", desc: "Romantic storytelling.", image: "/prewedding.jpg" },
  { title: "Cinematic Films", desc: "Luxury film experience.", image: "/cinematic.jfif" },
  { title: "Wedding", desc: "Complete coverage.", image: "/wedding.jfif" },
];

const AnimatedLetter = ({ char, progress, index, total, className }) => {
  const startEnter = (index / total) * 0.1;
  const endEnter = startEnter + 0.05;

  const reverseIndex = total - 1 - index;
  const startExit = 0.85 + (reverseIndex / total) * 0.1;
  const endExit = startExit + 0.05;

  const opacity = useTransform(
    progress,
    [startEnter, endEnter, startExit, endExit],
    [0, 1, 1, 0]
  );

  const y = useTransform(
    progress,
    [startEnter, endEnter, startExit, endExit],
    [100, 0, 0, 100]
  );

  return (
    <motion.span
      style={{ opacity, y, display: "inline-block" }}
      className={className}
    >
      {char === " " ? "\u00A0" : char}
    </motion.span>
  );
};

export default function SwagStyleCards() {
  const containerRef = useRef(null);

  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"],
  });

  const smoothProgress = useSpring(scrollYProgress, {
    stiffness: 60,
    damping: 20,
    restDelta: 0.001,
  });

  const word1 = "OUR".split("");
  const word2 = "SERVICES".split("");
  const totalLength = word1.length + word2.length;

  return (
    <section ref={containerRef} className="relative h-[500vh] bg-white">
      {/* Huge Sticky Text behind cards */}
      <div
        className="sticky top-0 h-screen w-full flex items-center justify-center overflow-hidden z-0 pointer-events-none"
      >
        <h1 className="text-[12vw] font-playfair text-center uppercase tracking-widest leading-none drop-shadow-sm select-none whitespace-nowrap flex">
          <span className="text-hom-gold pr-6 flex">
            {word1.map((char, i) => (
              <AnimatedLetter
                key={`w1-${i}`}
                char={char}
                progress={smoothProgress}
                index={i}
                total={totalLength}
              />
            ))}
          </span>
          <span className="text-black flex">
            {word2.map((char, i) => (
              <AnimatedLetter
                key={`w2-${i}`}
                char={char}
                progress={smoothProgress}
                index={word1.length + i}
                total={totalLength}
              />
            ))}
          </span>
        </h1>
      </div>

      {/* Cards Overlay */}
      <div className="absolute top-0 left-0 w-full h-[500vh]">
        <div className="sticky top-0 h-screen w-full flex items-center justify-center z-10">
          <div className="relative w-[340px] h-[480px]">
            {cards.map((card, i) => {
              const start = i * 0.2;
              const end = start + 0.2;

              const baseRotation = i === 0 ? 0 : i % 2 === 0 ? i * -3 : i * 3;

              const y = useTransform(
                smoothProgress,
                [start, end],
                [0, -800]
              );

              const rotate = useTransform(
                smoothProgress,
                [start, end],
                [baseRotation, baseRotation - 30]
              );

              const opacity = useTransform(
                smoothProgress,
                [start, end - 0.05, end],
                [1, 1, 0]
              );

              return (
                <motion.div
                  key={i}
                  style={{
                    y,
                    rotate,
                    opacity,
                    zIndex: cards.length - i,
                  }}
                  className={`absolute w-full h-full rounded-[3rem] text-hom-gold shadow-2xl flex flex-col justify-end border border-zinc-200/10 origin-bottom overflow-hidden bg-black`}
                >
                  <Image
                    src={card.image}
                    alt={card.title}
                    fill
                    className="object-cover z-0"
                  />
                  {/* Subtle gradient overlay to make text pop against the image */}
                  <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/10 to-transparent z-10 pointer-events-none" />

                  <div className="relative z-20 p-8 flex items-end justify-between">
                    <div>
                      <h3 className="text-3xl font-bold mb-2 font-aboreto tracking-wider">
                        {card.title}
                      </h3>

                    </div>

                    {/* Arrow Button */}
                    <motion.div
                      whileHover={{ scale: 1.1 }}
                      whileTap={{ scale: 0.95 }}
                      className="flex-shrink-0 w-12 h-12 min-w-[48px] min-h-[48px] rounded-full border border-hom-gold flex items-center justify-center bg-white/10 backdrop-blur-md transition duration-300 group"
                    >
                      <svg
                        xmlns="http://www.w3.org/2000/svg"
                        className="w-5 h-5 text-hom-gold group-hover:text-hom-gold transition"
                        viewBox="0 0 24 24"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="2"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          d="M7 17L17 7M17 7H8M17 7V16"
                        />
                      </svg>
                    </motion.div>
                  </div>
                </motion.div>
              );
            })}
          </div>
        </div>
      </div>
    </section>
  );
}
